//! Fixture replay for the beta activity-center projection.
//!
//! The fixtures live under `fixtures/ux/m3/activity_center/` and are
//! generated by the `aureline_shell_activity_center` CLI bin so the
//! checked-in JSON stays a literal projection of the seeded
//! `ActivityCenterBetaPage` (no hand-written drift).

use aureline_shell::activity_center::alpha::ActivityJobFamily;
use aureline_shell::activity_center::beta::{
    seeded_activity_center_beta_page, validate_activity_center_beta_page,
    validate_activity_center_beta_support_export, ActivityCenterBetaBadge, ActivityCenterBetaPage,
    ActivityCenterBetaRow, ActivityCenterBetaSupportExport, AuthoritativeReopenClass,
    ACTIVITY_CENTER_BETA_SCHEMA_VERSION, ACTIVITY_CENTER_BETA_SHARED_CONTRACT_REF,
};

const FIXTURE_DIR: &str = concat!(
    env!("CARGO_MANIFEST_DIR"),
    "/../../fixtures/ux/m3/activity_center"
);

fn load<T: serde::de::DeserializeOwned>(filename: &str) -> T {
    let path = format!("{}/{}", FIXTURE_DIR, filename);
    let body =
        std::fs::read_to_string(&path).unwrap_or_else(|err| panic!("failed to read {path}: {err}"));
    serde_json::from_str(&body).unwrap_or_else(|err| panic!("failed to parse {path}: {err}"))
}

#[test]
fn fixtures_round_trip_through_shared_types() {
    let rows: Vec<ActivityCenterBetaRow> = load("rows.json");
    assert!(!rows.is_empty(), "rows fixture must seed at least one row");
    for row in &rows {
        assert_eq!(
            row.shared_contract_ref,
            ACTIVITY_CENTER_BETA_SHARED_CONTRACT_REF
        );
        assert_eq!(row.schema_version, ACTIVITY_CENTER_BETA_SCHEMA_VERSION);
        assert!(
            row.toast_independence.recoverable_without_toast,
            "{} must be recoverable without a toast",
            row.row_id
        );
        assert!(
            row.toast_independence.reopenable_after_toast_expiry,
            "{} must remain reopenable after the toast expires",
            row.row_id
        );
        match row.reopen_class {
            AuthoritativeReopenClass::ExactDurableObject => assert!(
                row.exact_target_identity_ref
                    .as_ref()
                    .is_some_and(|s| !s.is_empty()),
                "{} promises exact reopen but carries no identity ref",
                row.row_id
            ),
            AuthoritativeReopenClass::TruthfulPlaceholder => assert!(
                row.placeholder_reason_label
                    .as_ref()
                    .is_some_and(|s| !s.is_empty()),
                "{} promises placeholder reopen but carries no reason label",
                row.row_id
            ),
            AuthoritativeReopenClass::DeniedAndExplained => assert!(
                row.denial_reason_label
                    .as_ref()
                    .is_some_and(|s| !s.is_empty()),
                "{} promises denied reopen but carries no reason label",
                row.row_id
            ),
        }
    }

    let badges: Vec<ActivityCenterBetaBadge> = load("badges.json");
    assert_eq!(
        badges.len(),
        rows.len(),
        "badge mirror must cover every row exactly once"
    );
    for badge in &badges {
        let row = rows
            .iter()
            .find(|r| r.row_id == badge.row_id)
            .unwrap_or_else(|| panic!("badge {} has no matching row", badge.row_id));
        assert_eq!(badge.job_family, row.job_family);
        assert_eq!(badge.state_class, row.state_class);
        assert_eq!(badge.resolution_class, row.resolution_class);
        assert_eq!(badge.activity_partition, row.activity_partition);
    }

    let mut covered_families: Vec<ActivityJobFamily> = rows.iter().map(|r| r.job_family).collect();
    covered_families.sort();
    covered_families.dedup();
    for required in [
        ActivityJobFamily::Indexing,
        ActivityJobFamily::Restore,
        ActivityJobFamily::InstallUpdate,
        ActivityJobFamily::TaskRun,
        ActivityJobFamily::TestRun,
        ActivityJobFamily::GitReview,
    ] {
        assert!(
            covered_families.contains(&required),
            "rows must cover required job family {}",
            required.as_str()
        );
    }

    let page: ActivityCenterBetaPage = load("page.json");
    assert_eq!(
        page.shared_contract_ref,
        ACTIVITY_CENTER_BETA_SHARED_CONTRACT_REF
    );
    assert_eq!(page.rows.len(), rows.len());
    assert_eq!(page.badges.len(), badges.len());
    validate_activity_center_beta_page(&page).expect("page must validate");

    let export: ActivityCenterBetaSupportExport = load("support_export.json");
    assert_eq!(
        export.shared_contract_ref,
        ACTIVITY_CENTER_BETA_SHARED_CONTRACT_REF
    );
    assert_eq!(export.rows.len(), page.rows.len());
    let expected_case_ids: Vec<String> = page.rows.iter().map(|r| r.case_id.clone()).collect();
    assert_eq!(export.case_ids, expected_case_ids);
    assert!(export.raw_private_material_excluded);
    validate_activity_center_beta_support_export(&export)
        .expect("support export must validate against its embedded page");
}

#[test]
fn page_fixture_matches_seeded_builder() {
    let from_file: ActivityCenterBetaPage = load("page.json");
    let from_code = seeded_activity_center_beta_page();
    assert_eq!(
        from_file, from_code,
        "fixture must be a literal projection of the seeded page; regenerate via the headless bin"
    );
}
